import { readdir, readFile } from "node:fs/promises";
import { join, posix as path, relative } from "node:path";

export type KnowledgeGraphNodeType = "root" | "folder" | "document" | "tag";
export type KnowledgeGraphEdgeType = "contains" | "references" | "tagged";

export interface KnowledgeGraphNode {
  id: string;
  label: string;
  type: KnowledgeGraphNodeType;
  path?: string;
  url?: string;
  summary?: string;
  tags?: string[];
  size?: number;
}

export interface KnowledgeGraphEdge {
  id: string;
  source: string;
  target: string;
  type: KnowledgeGraphEdgeType;
  label: string;
}

export interface KnowledgeGraphPayload {
  generatedAt: string;
  owner: string;
  repo: string;
  branch: string;
  root: string;
  sourceUrl: string;
  nodes: KnowledgeGraphNode[];
  edges: KnowledgeGraphEdge[];
  stats: {
    folders: number;
    documents: number;
    tags: number;
    references: number;
  };
  error?: string;
}

interface GitHubTreeItem {
  path: string;
  type: "blob" | "tree";
  sha: string;
  size?: number;
}

interface DocumentSource {
  item: GitHubTreeItem;
  content: string;
  title: string;
  summary: string;
  tags: string[];
}

const DEFAULT_OWNER = "mikeminer";
const DEFAULT_REPO = "Italian-OSS-Legal-Platform";
const DEFAULT_BRANCH = "dev";
const DEFAULT_ROOT = "docs/okf";
const FALLBACK_BRANCHES = ["codex/knowledge-base-docs", "main", "master"];
const FALLBACK_ROOTS = ["knowledge"];
const API_BASE = "https://api.github.com";

export async function loadKnowledgeGraphFromGitHub(
  env: NodeJS.ProcessEnv = process.env
): Promise<KnowledgeGraphPayload> {
  const owner = env.KNOWLEDGE_REPO_OWNER ?? DEFAULT_OWNER;
  const repo = env.KNOWLEDGE_REPO_NAME ?? DEFAULT_REPO;
  const requestedBranch = env.KNOWLEDGE_BRANCH ?? DEFAULT_BRANCH;
  const requestedRoot = normalizePath(env.KNOWLEDGE_ROOT ?? DEFAULT_ROOT);
  const branchCandidates = unique([requestedBranch, ...FALLBACK_BRANCHES]);
  const rootCandidates = unique([requestedRoot, ...FALLBACK_ROOTS]);
  let lastError = "";

  for (const branch of branchCandidates) {
    const headers = createGitHubHeaders(env.GITHUB_TOKEN);
    try {
      const treeSha = await fetchBranchTreeSha({ owner, repo, branch, headers });
      const tree = await fetchRepositoryTree({ owner, repo, sha: treeSha, headers });

      for (const root of rootCandidates) {
        const markdownItems = tree.filter(
          (item) =>
            item.type === "blob" &&
            item.path.startsWith(`${root}/`) &&
            /\.(md|mdx)$/i.test(item.path)
        );

        if (!markdownItems.length) {
          lastError = `Nessun documento Markdown in ${branch}/${root}`;
          continue;
        }

        const sources = await Promise.all(
          markdownItems.map(async (item) => ({
            item,
            content: await fetchBlobContent({ owner, repo, sha: item.sha, headers })
          }))
        );

        return buildKnowledgeGraph({
          owner,
          repo,
          branch,
          root,
          sourceUrl: githubTreeUrl(owner, repo, branch, root),
          documents: sources.map(({ item, content }) => createDocumentSource(item, content))
        });
      }
    } catch (error) {
      lastError = error instanceof Error ? error.message : "Errore sconosciuto";
    }
  }

  for (const root of rootCandidates) {
    try {
      const documents = await loadDocumentsFromFilesystem(root);
      if (documents.length) {
        return buildKnowledgeGraph({
          owner,
          repo,
          branch: requestedBranch,
          root,
          sourceUrl: githubTreeUrl(owner, repo, requestedBranch, root),
          documents
        });
      }
    } catch (error) {
      lastError = error instanceof Error ? error.message : lastError;
    }
  }

  return createErrorGraph({
      owner,
      repo,
      branch: requestedBranch,
      root: requestedRoot,
      sourceUrl: githubTreeUrl(owner, repo, requestedBranch, requestedRoot),
      error: lastError || "Knowledge base non trovata"
    });
}

async function fetchBranchTreeSha(input: {
  owner: string;
  repo: string;
  branch: string;
  headers: HeadersInit;
}): Promise<string> {
  const response = await fetch(
    `${API_BASE}/repos/${input.owner}/${input.repo}/branches/${encodeURIComponent(input.branch)}`,
    {
      headers: input.headers,
      next: { revalidate: 900 }
    }
  );

  if (!response.ok) {
    throw new Error(`Branch GitHub non leggibile (${response.status})`);
  }

  const payload = (await response.json()) as { commit?: { commit?: { tree?: { sha?: string } } } };
  if (!payload.commit?.commit?.tree?.sha) {
    throw new Error("La risposta GitHub non contiene lo SHA dell'albero");
  }

  return payload.commit.commit.tree.sha;
}

async function fetchRepositoryTree(input: {
  owner: string;
  repo: string;
  sha: string;
  headers: HeadersInit;
}): Promise<GitHubTreeItem[]> {
  const response = await fetch(
    `${API_BASE}/repos/${input.owner}/${input.repo}/git/trees/${input.sha}?recursive=1`,
    {
      headers: input.headers,
      next: { revalidate: 900 }
    }
  );

  if (!response.ok) {
    throw new Error(`Albero GitHub non leggibile (${response.status})`);
  }

  const payload = (await response.json()) as { tree?: GitHubTreeItem[] };
  return payload.tree ?? [];
}

async function fetchBlobContent(input: {
  owner: string;
  repo: string;
  sha: string;
  headers: HeadersInit;
}): Promise<string> {
  const response = await fetch(
    `${API_BASE}/repos/${input.owner}/${input.repo}/git/blobs/${input.sha}`,
    {
      headers: input.headers,
      next: { revalidate: 900 }
    }
  );

  if (!response.ok) {
    throw new Error(`Documento knowledge non leggibile (${response.status})`);
  }

  const payload = (await response.json()) as { content?: string; encoding?: string };
  if (payload.encoding !== "base64" || !payload.content) {
    throw new Error("Blob GitHub in formato non supportato");
  }

  return Buffer.from(payload.content.replace(/\n/g, ""), "base64").toString("utf8");
}

async function loadDocumentsFromFilesystem(root: string): Promise<DocumentSource[]> {
  const repositoryRoot = process.cwd();
  const rootDir = localRootDirectory(repositoryRoot, root);
  if (!rootDir) {
    return [];
  }

  const filePaths = await walkMarkdownFiles(rootDir);

  return Promise.all(
    filePaths.map(async (filePath) => {
      const content = await readFile(filePath, "utf8");
      const relativePath = normalizePath(relative(repositoryRoot, filePath));
      const item: GitHubTreeItem = {
        path: relativePath,
        type: "blob",
        sha: `local:${relativePath}`,
        size: Buffer.byteLength(content)
      };

      return createDocumentSource(item, content);
    })
  );
}

function localRootDirectory(repositoryRoot: string, root: string): string | undefined {
  if (root === "docs/okf") {
    return join(repositoryRoot, "docs", "okf");
  }

  if (root === "knowledge") {
    return join(repositoryRoot, "knowledge");
  }

  return undefined;
}

async function walkMarkdownFiles(directory: string): Promise<string[]> {
  const entries = await readdir(directory, { withFileTypes: true });
  const files = await Promise.all(
    entries.map(async (entry) => {
      const entryPath = join(directory, entry.name);
      if (entry.isDirectory()) {
        return walkMarkdownFiles(entryPath);
      }

      return /\.(md|mdx)$/i.test(entry.name) ? [entryPath] : [];
    })
  );

  return files.flat();
}

function createDocumentSource(item: GitHubTreeItem, content: string): DocumentSource {
  const frontmatter = extractFrontmatter(content);

  return {
    item,
    content,
    title: frontmatter.title ?? extractHeading(content) ?? titleFromPath(item.path),
    summary: frontmatter.description ?? extractSummary(content),
    tags: frontmatter.tags
  };
}

function buildKnowledgeGraph(input: {
  owner: string;
  repo: string;
  branch: string;
  root: string;
  sourceUrl: string;
  documents: DocumentSource[];
}): KnowledgeGraphPayload {
  const nodes = new Map<string, KnowledgeGraphNode>();
  const edges = new Map<string, KnowledgeGraphEdge>();
  const documentIdsByPath = new Map<string, string>();

  const rootId = `root:${input.root}`;
  nodes.set(rootId, {
    id: rootId,
    label: input.root,
    type: "root",
    path: input.root,
    url: input.sourceUrl,
    summary: "Radice della knowledge base pubblicata sul branch GitHub."
  });

  for (const document of input.documents) {
    ensureFolderChain({ nodes, edges, root: input.root, filePath: document.item.path });

    const docId = `doc:${document.item.path}`;
    documentIdsByPath.set(document.item.path, docId);
    nodes.set(docId, {
      id: docId,
      label: document.title,
      type: "document",
      path: document.item.path,
      url: githubFileUrl(input.owner, input.repo, input.branch, document.item.path),
      summary: document.summary,
      tags: document.tags,
      size: document.item.size
    });

    const folderPath = path.dirname(document.item.path);
    addEdge(edges, {
      source: folderPath === "." ? rootId : `folder:${folderPath}`,
      target: docId,
      type: "contains",
      label: "contiene"
    });
  }

  for (const document of input.documents) {
    const docId = documentIdsByPath.get(document.item.path);
    if (!docId) {
      continue;
    }

    for (const tag of document.tags) {
      const tagId = tagNodeId(tag);
      if (!nodes.has(tagId)) {
        nodes.set(tagId, {
          id: tagId,
          label: tag,
          type: "tag",
          summary: "Concetto ricorrente nel frontmatter della knowledge base."
        });
      }

      addEdge(edges, {
        source: docId,
        target: tagId,
        type: "tagged",
        label: "tema"
      });
    }

    for (const targetPath of extractMarkdownTargets(document.content, document.item.path)) {
      const targetId = documentIdsByPath.get(targetPath);
      if (targetId && targetId !== docId) {
        addEdge(edges, {
          source: docId,
          target: targetId,
          type: "references",
          label: "rimanda a"
        });
      }
    }
  }

  const nodeList = [...nodes.values()];
  const edgeList = [...edges.values()];

  return {
    generatedAt: new Date().toISOString(),
    owner: input.owner,
    repo: input.repo,
    branch: input.branch,
    root: input.root,
    sourceUrl: input.sourceUrl,
    nodes: nodeList,
    edges: edgeList,
    stats: {
      folders: nodeList.filter((node) => node.type === "folder").length,
      documents: nodeList.filter((node) => node.type === "document").length,
      tags: nodeList.filter((node) => node.type === "tag").length,
      references: edgeList.filter((edge) => edge.type === "references").length
    }
  };
}

function ensureFolderChain(input: {
  nodes: Map<string, KnowledgeGraphNode>;
  edges: Map<string, KnowledgeGraphEdge>;
  root: string;
  filePath: string;
}) {
  const parts = path.dirname(input.filePath).split("/").filter(Boolean);
  let currentPath = "";
  let previousId = `root:${input.root}`;

  for (const part of parts) {
    currentPath = currentPath ? `${currentPath}/${part}` : part;
    if (currentPath === input.root) {
      previousId = `root:${input.root}`;
      continue;
    }

    const folderId = `folder:${currentPath}`;
    if (!input.nodes.has(folderId)) {
      input.nodes.set(folderId, {
        id: folderId,
        label: titleFromPath(currentPath),
        type: "folder",
        path: currentPath,
        summary: "Sezione della knowledge base."
      });
    }

    addEdge(input.edges, {
      source: previousId,
      target: folderId,
      type: "contains",
      label: "contiene"
    });
    previousId = folderId;
  }
}

function addEdge(
  edges: Map<string, KnowledgeGraphEdge>,
  edge: Omit<KnowledgeGraphEdge, "id">
) {
  const id = `${edge.type}:${edge.source}->${edge.target}`;
  edges.set(id, { ...edge, id });
}

function extractFrontmatter(content: string): {
  title?: string;
  description?: string;
  tags: string[];
} {
  const match = content.match(/^---\s*\n([\s\S]*?)\n---\s*/);
  if (!match) {
    return { tags: [] };
  }

  const frontmatter = match[1] ?? "";
  const title = frontmatter.match(/^title:\s*["']?(.+?)["']?\s*$/m)?.[1]?.trim();
  const description = frontmatter
    .match(/^(?:description|summary):\s*["']?(.+?)["']?\s*$/m)?.[1]
    ?.trim();
  const tags = extractTags(frontmatter);

  return { title, description, tags };
}

function extractTags(frontmatter: string): string[] {
  const inline = frontmatter.match(/^tags:\s*\[(.*?)\]\s*$/m)?.[1];
  if (inline) {
    return cleanTags(inline.split(","));
  }

  const block = frontmatter.match(/^tags:\s*\n((?:\s*-\s*.+\n?)+)/m)?.[1];
  if (block) {
    return cleanTags(
      block
        .split("\n")
        .map((line) => line.replace(/^\s*-\s*/, ""))
        .filter(Boolean)
    );
  }

  const single = frontmatter.match(/^tags:\s*(.+)$/m)?.[1];
  return single ? cleanTags(single.split(",")) : [];
}

function cleanTags(tags: string[]): string[] {
  return [...new Set(tags.map((tag) => stripQuotes(tag.trim())).filter(Boolean))];
}

function extractHeading(content: string): string | undefined {
  const heading = content.match(/^#\s+(.+)$/m)?.[1]?.trim();
  return heading ? stripMarkdown(heading) : undefined;
}

function extractSummary(content: string): string {
  const withoutFrontmatter = content.replace(/^---\s*\n[\s\S]*?\n---\s*/, "");
  const paragraph = withoutFrontmatter
    .split(/\n{2,}/)
    .map((part) => part.trim())
    .find((part) => part && !part.startsWith("#") && !part.startsWith("|"));

  return stripMarkdown(paragraph ?? "").slice(0, 220);
}

function extractMarkdownTargets(content: string, sourcePath: string): string[] {
  const targets = new Set<string>();
  const sourceDir = path.dirname(sourcePath);
  const linkPattern = /\[[^\]]+\]\(([^)#]+)(?:#[^)]+)?\)/g;
  let match: RegExpExecArray | null;

  while ((match = linkPattern.exec(content)) !== null) {
    const href = match[1]?.trim();
    if (!href) {
      continue;
    }
    if (/^(?:https?:|mailto:|#)/i.test(href)) {
      continue;
    }

    const resolved = normalizePath(path.normalize(path.join(sourceDir, href)));
    if (/\.(md|mdx)$/i.test(resolved)) {
      targets.add(resolved);
    }
  }

  return [...targets];
}

function createGitHubHeaders(token?: string): HeadersInit {
  return {
    accept: "application/vnd.github+json",
    ...(token ? { authorization: `Bearer ${token}` } : {})
  };
}

function unique<T>(values: T[]): T[] {
  return [...new Set(values.filter(Boolean))];
}

function createErrorGraph(input: {
  owner: string;
  repo: string;
  branch: string;
  root: string;
  sourceUrl: string;
  error: string;
}): KnowledgeGraphPayload {
  return {
    generatedAt: new Date().toISOString(),
    owner: input.owner,
    repo: input.repo,
    branch: input.branch,
    root: input.root,
    sourceUrl: input.sourceUrl,
    nodes: [
      {
        id: `root:${input.root}`,
        label: input.root,
        type: "root",
        path: input.root,
        url: input.sourceUrl,
        summary: "La knowledge base GitHub non e' stata leggibile in questo momento."
      }
    ],
    edges: [],
    stats: { folders: 0, documents: 0, tags: 0, references: 0 },
    error: input.error
  };
}

function githubFileUrl(owner: string, repo: string, branch: string, filePath: string): string {
  return `https://github.com/${owner}/${repo}/blob/${branch}/${filePath}`;
}

function githubTreeUrl(owner: string, repo: string, branch: string, root: string): string {
  return `https://github.com/${owner}/${repo}/tree/${branch}/${root}`;
}

function tagNodeId(tag: string): string {
  return `tag:${tag.toLowerCase().replace(/[^a-z0-9-]+/gi, "-")}`;
}

function titleFromPath(value: string): string {
  const fileName = path.basename(value).replace(/\.(md|mdx)$/i, "");
  return fileName
    .split(/[-_]/)
    .filter(Boolean)
    .map((part) => part.slice(0, 1).toUpperCase() + part.slice(1))
    .join(" ");
}

function stripMarkdown(value: string): string {
  return value
    .replace(/`([^`]+)`/g, "$1")
    .replace(/\*\*([^*]+)\*\*/g, "$1")
    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
    .replace(/[>#*_]/g, "")
    .trim();
}

function stripQuotes(value: string): string {
  return value.replace(/^["']|["']$/g, "");
}

function normalizePath(value: string): string {
  return value.replace(/\\/g, "/").replace(/^\/+/, "").replace(/\/+$/, "");
}
